import React, { useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [editingId, setEditingId] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    if (editingId) {
      setLinks(
        links.map((link) =>
          link.id === editingId ? { ...link, name } : link
        )
      );
      setEditingId(null);
    } else {
      setLinks([...links, { id: Date.now(), name }]);
    }

    setName("");
  };

  const handleEdit = (link) => {
    setName(link.name);
    setEditingId(link.id);
  };

  const handleDelete = (id) => {
    setLinks(links.filter((link) => link.id !== id));
  };

  return (
    <div className={design.wrapper}>
      <div className={design.container}>
        
        {/* HEADER */}
        <div className={design.header}>
          <h1 className={design.title}>Link Management</h1>
        </div>

        {/* FORM */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className={design.card}
        >
          <form onSubmit={handleSubmit} className={design.formWrapper}>
            <input
              type="text"
              placeholder="Enter link name..."
              value={name}
              onChange={(e) => setName(e.target.value)}
              className={design.input}
            />

            <motion.button
              whileTap={{ scale: 0.95 }}
              type="submit"
              className={design.button}
            >
              <Plus size={16} />
              {editingId ? "Update Link" : "Add Link"}
            </motion.button>
          </form>
        </motion.div>

        {/* TABLE */}
        <div className={`${design.card} ${design.tableWrapper}`}>
          
          {/* Desktop Header */}
          <div className={design.tableHeader}>
            <div className="flex-1">Name</div>
            <div>Actions</div>
          </div>

          <AnimatePresence>
            {links.length === 0 ? (
              <div className={design.emptyState}>
                No links created yet.
              </div>
            ) : (
              links.map((link) => (
                <motion.div
                  key={link.id}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, x: -20 }}
                  transition={{ duration: 0.2 }}
                >
                  {/* Desktop Row */}
                  <div className={design.rowDesktop}>
                    <span className="text-slate-700 font-medium">
                      {link.name}
                    </span>

                    <div className="flex gap-4">
                      <button
                        onClick={() => handleEdit(link)}
                        className="text-indigo-600 hover:text-indigo-800"
                      >
                        <Pencil size={18} />
                      </button>

                      <button
                        onClick={() => handleDelete(link.id)}
                        className="text-red-600 hover:text-red-800"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>

                  {/* Mobile Card */}
                  <div className={design.rowMobile}>
                    <div className="text-slate-700 font-medium">
                      {link.name}
                    </div>

                    <div className="flex gap-4">
                      <button
                        onClick={() => handleEdit(link)}
                        className="text-indigo-600"
                      >
                        <Pencil size={18} />
                      </button>

                      <button
                        onClick={() => handleDelete(link.id)}
                        className="text-red-600"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </div>
                </motion.div>
              ))
            )}
          </AnimatePresence>
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
